<?php
namespace App\Filament\Resources;
use App\Filament\Resources\FaqResource\Pages;use App\Models\Faq;use Filament\Actions\BulkActionGroup;use Filament\Actions\DeleteBulkAction;use Filament\Actions\EditAction;use Filament\Forms\Components\Select;use Filament\Forms\Components\Textarea;use Filament\Forms\Components\TextInput;use Filament\Forms\Components\Toggle;use Filament\Resources\Resource;use Filament\Schemas\Schema;use Filament\Tables\Columns\IconColumn;use Filament\Tables\Columns\TextColumn;use Filament\Tables\Table;
class FaqResource extends Resource{protected static ?string $model=Faq::class;protected static ?string $navigationLabel='FAQ';public static function form(Schema $schema):Schema{return $schema->components([Select::make('service_id')->label('სერვისი')->relationship('service','name')->searchable()->preload(),TextInput::make('context')->default('general')->required(),Textarea::make('question')->label('კითხვა')->required(),Textarea::make('answer')->label('პასუხი')->required()->rows(6),Toggle::make('is_active')->default(true),TextInput::make('sort_order')->numeric()->default(0)]);}public static function table(Table $table):Table{return $table->columns([TextColumn::make('question')->searchable()->limit(70),TextColumn::make('service.name')->label('სერვისი'),TextColumn::make('context'),IconColumn::make('is_active')->boolean()])->defaultSort('sort_order')->recordActions([EditAction::make()])->toolbarActions([BulkActionGroup::make([DeleteBulkAction::make()])]);}public static function getPages():array{return ['index'=>Pages\ListFaqs::route('/'),'create'=>Pages\CreateFaq::route('/create'),'edit'=>Pages\EditFaq::route('/{record}/edit')];}}
